import sys
import time
import datetime
import subprocess
from threading import Thread

def read_tasks_from_file(file_path):
    tasks = []
    try:
        with open(file_path, 'r') as file:
            for line in file:
                parts = line.strip().split(',')
                if len(parts) == 3:
                    tasks.append({'time': parts[0], 'date': parts[1], 'command': parts[2]})
    except FileNotFoundError:
        print(f"No existing task file found at {file_path}. A new one will be created.")
    return tasks

def write_task_to_file(file_path, task):
    with open(file_path, 'a') as file:
        file.write(f"{task['time']},{task['date']},{task['command']}\n")

def execute_task(task):
    subprocess.run(task['command'], shell=True)

def task_scheduler_loop(tasks_file):
    while True:
        now = datetime.datetime.now()
        tasks = read_tasks_from_file(tasks_file)
        for task in tasks:
            task_time = datetime.datetime.strptime(f"{task['date']} {task['time']}", '%Y-%m-%d %H:%M')
            if now >= task_time:
                print(f"Executing task: {task['command']}")
                execute_task(task)
                tasks.remove(task)
        with open(tasks_file, 'w') as file:
            for task in tasks:
                file.write(f"{task['time']},{task['date']},{task['command']}\n")
        time.sleep(60)

def add_task(tasks_file, time, date, command):
    task = {'time': time, 'date': date, 'command': command}
    write_task_to_file(tasks_file, task)

def main():
    tasks_file = 'tasks.txt'
    if len(sys.argv) < 2:
